function openArtifactReward(){let evos=readyEvos(),owned=new Set([...S.bag,...S.artifacts]),choices=ARTIFACTS.filter(a=>!owned.has(a[0])).sort(()=>Math.random()-.5).slice(0,3);if(!choices.length&&!evos.length)return;S.paused=true;$('artifactChoiceSub').textContent=evos.length?'击败 魔王 固定获得 1 魔核。可优先进化已成型技能，也可拿通用神器。':'击败 魔王 固定获得 1 魔核，并额外选择一件通用神器奖励。';let evoHtml=evos.map(([id,e])=>`<button class="choice evoChoice" data-evolve="${id}"><h2>✦ 进化 · ${esc(e.name)}</h2><p>${INFO[e.main][0]} 等级${S.skills[e.main]} + ${INFO[e.support][0]} 等级${S.skills[e.support]}</p><p>${esc(e.desc)}</p><p class="rewardHint">${S.player.cls===e.job?'本职业完全适配，数值略高':'跨职业可用，效果略收敛'} / 替代一次神器选择</p></button>`).join('');let artHtml=choices.map(a=>{let i=ARTIFACTS.findIndex(v=>v[0]===a[0]);return `<button class="choice" data-reward-artifact="${a[0]}"><h2>${artIcon(i)} ${esc(a[1])}</h2><p>${esc(a[2])}</p><p class="rewardHint">魔王 奖励：直接收入背包，可在物品栏装备。</p></button>`}).join('');$('artifactChoices').innerHTML=evoHtml+artHtml;$('artifactChoice').classList.remove('hidden')}
function takeArtifactReward(id){if(!S.bag.includes(id)&&!S.artifacts.includes(id)&&S.bag.length<24)S.bag.push(id);$('artifactChoice').classList.add('hidden');saveGame();S.paused=false}
function showNotice(text){let el=$('notice');if(S){S.noticeText=text;S.notice=2.8}if(el){el.textContent=text;el.classList.remove('hidden')}}
function updateFeedback(dt){let p=S.player;if(S.notice>0){S.notice-=dt;if(S.notice<=0)$('notice').classList.add('hidden')}else $('notice').classList.add('hidden');$('lowHp').classList.toggle('hidden',!(p&&p.hp/p.max<.28&&!S.paused&&!S.over))}
function endlessBossGap(layer){return Math.max(260,Math.round(320+Math.min(layer,9)*85))}
function killProgressValue(e){if(!S?.endless||S.endlessLayer<9||e.boss)return 1;if(e.shield>0||e.type==='shield')return 50;if(e.elite)return 10;return 2}
function bossKillNeed(n){let need=0;for(let i=0;i<=n;i++){let step=i<2?160*(i+1):2400+(Math.min(i,4)-2)*120;need+=step}return need}
function nextBossNeed(){return S?.endless?(S.nextBossKills||S.kills+endlessBossGap(S.endlessLayer||1)):bossKillNeed(S.bossKills||0)}
function ensureEndlessBossTrack(){if(!S?.endless)return;if(S.endlessBossStartKills==null)S.endlessBossStartKills=Math.max(0,(S.nextBossKills||S.kills+endlessBossGap(S.endlessLayer||1))-endlessBossGap(S.endlessLayer||1));let need=endlessBossGap(S.endlessLayer||1),left=(S.nextBossKills||S.kills+need)-S.kills;if(left>need){S.endlessBossStartKills=S.kills;S.nextBossKills=S.kills+need}}
function updateBossWarn(){if(S?.endless)ensureEndlessBossTrack();let need=S.nextBossKills??nextBossNeed(),left=need-S.kills,el=$('bossWarn');if(left>0&&left<=8&&!S.paused&&!S.over){el.textContent=S.endless?`无尽第 ${S.endlessLayer} 层魔王即将降临，还需击杀 ${left}`:`魔王即将降临，还需击杀 ${left}`;el.classList.remove('hidden')}else el.classList.add('hidden')}
